{
  "__faion_header__": {
    "methodology": "vui-market-context",
    "version": "1.1.0",
    "produces": "decision-record"
  },
  "decision_date": "2026-05-23",
  "use_case": "smart-home",
  "scoring": [
    {
      "platform": "matter",
      "install_base": 4,
      "developer_access": "open",
      "distribution": 5,
      "evidence_sources": [
        "Matter spec 1.3 (2025)",
        "CSA 2025 update"
      ]
    },
    {
      "platform": "alexa",
      "install_base": 5,
      "developer_access": "restricted",
      "distribution": 3,
      "evidence_sources": [
        "Amazon 2025 dev portal"
      ]
    },
    {
      "platform": "home-assistant",
      "install_base": 3,
      "developer_access": "open",
      "distribution": 4,
      "evidence_sources": [
        "HA 2025 release notes"
      ]
    }
  ],
  "recommendation": {
    "primary": "matter",
    "fallback": [
      "home-assistant"
    ],
    "rationale": "Matter is consumed by Alexa/Google/Apple; primary gives multi-vendor reach with open access. Home Assistant fallback covers prosumers.",
    "lock_in_risk_notes": [
      "Matter v1.x ecosystem still maturing; expect feature gaps for advanced devices.",
      "Alexa-specific routines lost on Matter-only path."
    ]
  }
}
